import React, { useState } from "react";
import { Camera, CameraResultType, CameraSource } from "@capacitor/camera";

function App() {
  const [photo, setPhoto] = useState(null);
  const [uploading, setUploading] = useState(false);

  // 사진 촬영
  const takePhoto = async () => {
    try {
      const image = await Camera.getPhoto({
        quality: 90,
        allowEditing: true,
        resultType: CameraResultType.Uri,
        source: CameraSource.Camera,
        saveToGallery: true,
      });
      setPhoto(image.webPath);
    } catch (err) {
      console.error("카메라 오류:", err);
    }
  };

  // 사진 삭제
  const deletePhoto = () => {
    setPhoto(null);
  };

  // 서버 전송 (데모)
  const uploadPhoto = async () => {
    if (!photo) return;
    setUploading(true);

    // 실제 전송 로직이 들어갈 자리 (setTimeout으로 전송 중인 척!)
    setTimeout(() => {
      setUploading(false);
      alert("서버 전송이 완료되었습니다!");
      setPhoto(null);
    }, 1500);
  };

  return (
    <div style={wrapperStyle}>
      {/* 상단 바 */}
      <header style={headerStyle}>
        <h2 style={{ fontSize: "18px", margin: 0 }}>이미지 업로더</h2>
      </header>

      <main style={mainStyle}>
        {/* 사진 표시 영역 */}
        <div style={photoCardStyle}>
          {photo ? (
            <>
              <img src={photo} alt="Preview" style={imageStyle} />
              <button onClick={deletePhoto} style={closeButtonStyle}>
                ✕
              </button>
            </>
          ) : (
            <div style={placeholderStyle} onClick={takePhoto}>
              <span style={{ fontSize: "40px", marginBottom: "10px" }}>📸</span>
              <p style={{ margin: 0, color: "#888" }}>클릭하여 사진 촬영</p>
            </div>
          )}
        </div>

        {/* 상태 안내 메시지 */}
        <div style={statusStyle}>
          {photo ? "사진이 준비되었습니다." : "업로드할 사진을 찍어주세요."}
        </div>
      </main>

      {/* 하단 버튼 영역 */}
      <footer style={footerStyle}>
        {!photo ? (
          <button onClick={takePhoto} style={mainButtonStyle}>
            사진 찍기
          </button>
        ) : (
          <button
            onClick={uploadPhoto}
            style={{ ...mainButtonStyle, backgroundColor: "#28a745" }}
            disabled={uploading}
          >
            {uploading ? "전송 중..." : "서버로 전송하기"}
          </button>
        )}
      </footer>
    </div>
  );
}

// --- 현실적이고 깔끔한 스타일 ---

const wrapperStyle = {
  backgroundColor: "#f8f9fa",
  minHeight: "100vh",
  display: "flex",
  flexDirection: "column",
  fontFamily: "-apple-system, sans-serif",
};

const headerStyle = {
  height: "60px",
  backgroundColor: "#fff",
  display: "flex",
  alignItems: "center",
  justifyContent: "center",
  borderBottom: "1px solid #eee",
};

const mainStyle = {
  flex: 1,
  padding: "20px",
  display: "flex",
  flexDirection: "column",
  alignItems: "center",
};

const photoCardStyle = {
  width: "100%",
  maxWidth: "350px",
  aspectRatio: "3/4",
  backgroundColor: "#fff",
  borderRadius: "16px",
  boxShadow: "0 4px 12px rgba(0,0,0,0.08)",
  position: "relative",
  overflow: "hidden",
  display: "flex",
  alignItems: "center",
  justifyContent: "center",
  cursor: "pointer",
};

const imageStyle = {
  width: "100%",
  height: "100%",
  objectFit: "cover",
};

const placeholderStyle = {
  textAlign: "center",
};

const closeButtonStyle = {
  position: "absolute",
  top: "15px",
  right: "15px",
  width: "30px",
  height: "30px",
  borderRadius: "50%",
  backgroundColor: "rgba(0,0,0,0.5)",
  color: "#fff",
  border: "none",
  cursor: "pointer",
  fontSize: "16px",
};

const statusStyle = {
  marginTop: "20px",
  color: "#666",
  fontSize: "14px",
};

const footerStyle = {
  padding: "20px",
  backgroundColor: "#fff",
  borderTop: "1px solid #eee",
};

const mainButtonStyle = {
  width: "100%",
  padding: "16px",
  borderRadius: "12px",
  border: "none",
  backgroundColor: "#007bff",
  color: "#fff",
  fontSize: "16px",
  fontWeight: "bold",
  cursor: "pointer",
};

export default App;
